// ==============================================================
// WF7 - Convocar (monday)
// Recebe multipart/form-data do form web /convocar.
// Valida campos, monta column_values_json para o board ENTRADA
// (18413180912). Não dispara WF1 - operacional ativa coluna 'ativar'
// manualmente depois.
// ==============================================================

const BOARD_ENTRADA = 18413180912;
const GROUP_ID = 'topics';

// Colunas do board ENTRADA (Plan. de Intermitentes mensal/pontual)
const COL = {
  NOME_EMPREGADO:       'dropdown_mktadatt',  // dropdown - nome do empregado (chosenValues)
  CPF:                  'dup__of_matr_cula',  // text
  CHAPA:                'texto',              // text (Funcionário)
  FUNCAO:               'texto0',             // text
  ADMISSAO:             'text_mkzh8jhn',      // text (data string)
  ESCALA:               'text_mkvn2cmr',      // text
  SOLICITANTE:          'color_mktc9q29',     // status (OPERACIONAL/RH)
  CONTRATO:             'color_mktcnxwn',     // status
  LOCAL_UNIDADE:        'texto75',            // text legado
  LOCAL_UNIDADE_DROPDOWN: 'dropdown_mm3ts726', // dropdown global
  SABADO:               'color_mktaavmp',     // status SIM/NÃO
  INSALUBRIDADE:        'color_mktq63xa',     // status SIM/NÃO/NÃO INFORMADO
  INTERIOR:             'color__1',           // status SIM/NÃO
  TIPO_CONVOCACAO:      'color_mkta71ex',     // status (PONTUAL fixo)
  DATA_INICIO:          'date_mktayxhb',      // date
  DATA_FIM:             'date_mktasnwq',      // date
  JUSTIFICATIVA:        'color_mktarrgs',     // status
  EMPREGADO_SUBSTITUIDO:'text_mktc23av',      // text
  STATUS_CONVOCACAO:      'color_mm3a8ana',     // status Valida/Cancelada/Bloqueada - conflito
  CANCELAMENTO_INICIO: 'date_mm3b88ta',     // inicio do cancelamento parcial
  OPTANTE_VT: 'optante___vt',      // status SIM/NÃO/SIM*
  VT_SO_VOLTA: 'color_mkwaw840',   // status SIM/NÃO
};

const body = $input.first().json.body || {};

function str(v) { return (v === undefined || v === null) ? '' : String(v).trim(); }
function normalizeVtLabel(v) {
  const raw = str(v).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
  if (raw === 'SIM*') return 'SIM*';
  if (raw === 'SIM' || raw === 'TRUE' || raw === '1') return 'SIM';
  return 'NÃO';
}
function req(field) {
  const v = str(body[field]);
  if (!v) {
    throw new Error(`campo_obrigatorio:${field}`);
  }
  return v;
}

let payload;
try {
  payload = {
    name:                  req('name'),
    empregadoNome:         req('empregado_nome'),
    empregadoChapa:        str(body.empregado_chapa),
    empregadoCpf:          str(body.empregado_cpf),
    empregadoFuncao:       str(body.empregado_funcao),
    empregadoAdmissao:     str(body.empregado_admissao),
    escala:                req('escala'),
    solicitante:           req('solicitante'),
    contrato:              req('contrato'),
    localUnidade:          req('local_unidade'),
    sabado:                req('sabado'),
    insalubridade:         req('insalubridade'),
    interior:              req('interior'),
    dataInicio:            req('data_inicio'),
    dataFim:               req('data_fim'),
    justificativa:         req('justificativa'),
    empregadoSubstituido:  req('empregado_substituido'),
    optanteVt:            normalizeVtLabel(body.optante_vt ?? body.optanteVT ?? body.vale_transporte ?? body.valeTransporte ?? body.vt),
  };
} catch (e) {
  const msg = String(e.message || e);
  const m = msg.match(/^campo_obrigatorio:(.+)$/);
  return [{
    json: {
      _statusCode: 400,
      ok: false,
      erro: 'campo_obrigatorio',
      mensagem: m ? `Campo obrigatório ausente: ${m[1]}` : 'Payload inválido.'
    }
  }];
}

// Validação de datas
if (!/^\d{4}-\d{2}-\d{2}$/.test(payload.dataInicio) || !/^\d{4}-\d{2}-\d{2}$/.test(payload.dataFim)) {
  return [{ json: { _statusCode: 400, ok: false, erro: 'data_invalida', mensagem: 'Datas devem estar no formato YYYY-MM-DD.' } }];
}
if (payload.dataInicio > payload.dataFim) {
  return [{ json: { _statusCode: 400, ok: false, erro: 'data_invalida', mensagem: 'Data início > data fim.' } }];
}







