function normLabel(v) { return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase().replace(/[\.,;:/\\|_()\[\]{}-]+/g, ' ').replace(/\s+/g, ' ').trim(); }
function tokens(v) { return normLabel(v).split(' ').filter(t => t.length > 2); }
function unidadeValida(contrato, unidade) {
  const lista = UNIDADES_POR_CONTRATO[contrato] || [];
  const alvo = normLabel(unidade);
  if (lista.some(u => normLabel(u) === alvo)) return true;
  const alvoTokens = tokens(unidade);
  return lista.some(u => {
    const cand = normLabel(u);
    if (cand.includes(alvo) || alvo.includes(cand)) return true;
    const candTokens = tokens(u);
    const common = alvoTokens.filter(t => candTokens.includes(t)).length;
    return alvoTokens.length > 0 && common / alvoTokens.length >= 0.75;
  });
}
if (!unidadeValida(payload.contrato, payload.localUnidade)) {
  return [{ json: { _statusCode: 400, ok: false, erro: 'unidade_invalida', mensagem: 'Local/Unidade nao pertence ao contrato selecionado.' } }];
}

// Verifica binários (termos)
const binary = $input.first().binary || {};
const hasTermoConvocacao = !!binary.termo_convocacao;
const hasTermoInsalubridade = !!binary.termo_insalubridade;

// Monta column_values
const columnValues = {
  [COL.NOME_EMPREGADO]:      { labels: [payload.empregadoNome] },
  [COL.CPF]:                 payload.empregadoCpf,
  [COL.CHAPA]:               payload.empregadoChapa,
  [COL.FUNCAO]:              payload.empregadoFuncao,
  [COL.ADMISSAO]:            payload.empregadoAdmissao,
  [COL.ESCALA]:              payload.escala,
  [COL.SOLICITANTE]:         { label: payload.solicitante },
  [COL.CONTRATO]:            { label: payload.contrato },
  [COL.LOCAL_UNIDADE]:       payload.localUnidade,
  [COL.LOCAL_UNIDADE_DROPDOWN]: { labels: [payload.localUnidade] },
  [COL.SABADO]:              { label: payload.sabado },
  [COL.INSALUBRIDADE]:       { label: payload.insalubridade },
  [COL.INTERIOR]:            { label: payload.interior },
  [COL.TIPO_CONVOCACAO]:     { label: 'PONTUAL' },
  [COL.DATA_INICIO]:         { date: payload.dataInicio },
  [COL.DATA_FIM]:            { date: payload.dataFim },
  [COL.JUSTIFICATIVA]:       { label: payload.justificativa },
  [COL.EMPREGADO_SUBSTITUIDO]: payload.empregadoSubstituido,
  [COL.OPTANTE_VT]: { label: payload.optanteVt },
  [COL.VT_SO_VOLTA]: { label: payload.optanteVt === 'SIM*' ? 'SIM' : 'NÃO' },
  [COL.STATUS_CONVOCACAO]: { label: 'Válida' }
};

const conflictColumnId = payload.empregadoChapa ? COL.CHAPA : COL.NOME_EMPREGADO;
const conflictColumnValue = payload.empregadoChapa || payload.empregadoNome;
const mondayConflictQuery = {
  query: `query { items_page_by_column_values(limit: 100, board_id: ${BOARD_ENTRADA}, columns: [{ column_id: ${JSON.stringify(conflictColumnId)}, column_values: [${JSON.stringify(conflictColumnValue)}] }]) { items { id name column_values(ids: [${JSON.stringify(COL.NOME_EMPREGADO)}, ${JSON.stringify(COL.CHAPA)}, ${JSON.stringify(COL.DATA_INICIO)}, ${JSON.stringify(COL.DATA_FIM)}, ${JSON.stringify(COL.STATUS_CONVOCACAO)}, ${JSON.stringify(COL.CANCELAMENTO_INICIO)}]) { id text value } } } }`
};

return [{
  json: {
    _statusCode: 200,
    ok: true,
    name: payload.name,
    column_values_json: JSON.stringify(columnValues),
    empregadoNome: payload.empregadoNome,
    empregadoChapa: payload.empregadoChapa,
    dataInicio: payload.dataInicio,
    dataFim: payload.dataFim,
    localUnidade: payload.localUnidade,
    contrato: payload.contrato,
    empregadoCpf: payload.empregadoCpf,
    empregadoFuncao: payload.empregadoFuncao,
    empregadoAdmissao: payload.empregadoAdmissao,
    optanteVt: payload.optanteVt,
    mondayConflictQuery,
    hasTermoConvocacao,
    hasTermoInsalubridade,
    boardEntrada: BOARD_ENTRADA,
    groupId: GROUP_ID
  }
}];

// ==============================================================
// WF7 - Preparar uploads de arquivos
// Emite 0..2 items, um por arquivo presente, com o GraphQL multipart
// pronto para o nó HTTP Request do monday `/v2/file`.
// ==============================================================

const prep = $('Validar e preparar').first().json;
const monday = $input.first().json;
const webhookBinary = $('Webhook').first().binary || {};

const itemId = String(monday.id || monday.data?.create_item?.id || '');
if (!itemId) {
  // sem id, não conseguimos anexar; passa adiante sem uploads
  return [{ json: { _semUpload: true, itemId: '' } }];
}

const uploads = [];
if (prep.hasTermoConvocacao && webhookBinary.termo_convocacao) {
  uploads.push({
    binaryName: 'termo_convocacao',
    columnId: 'file_mm21x463',
    itemId
  });
}
if (prep.hasTermoInsalubridade && webhookBinary.termo_insalubridade) {
  uploads.push({
    binaryName: 'termo_insalubridade',
    columnId: 'file_mm21457r',
    itemId
  });
}

const query = 'mutation ($file: File!, $item_id: ID!, $column_id: String!) { add_file_to_column(item_id: $item_id, column_id: $column_id, file: $file) { id } }';

if (uploads.length === 0) {
  return [{ json: { _semUpload: true, itemId } }];
}

return uploads.map((u) => ({
  json: {
    _semUpload: false,
    itemId: u.itemId,
    columnId: u.columnId,
    binaryName: u.binaryName,
    graphqlQuery: query,
    variables: JSON.stringify({ file: null, item_id: u.itemId, column_id: u.columnId }),
    map: JSON.stringify({ '0': ['variables.file'] })
  },
  binary: { '0': $('Webhook').first().binary[u.binaryName] }
}));

// ==============================================================
// Trava de convocacao conflitante - WF7
// Respeita cancelamento parcial: somente o trecho ainda valido bloqueia.
// ==============================================================

const prep = $('Validar e preparar').first().json;
const response = $input.first().json || {};

if (Array.isArray(response.errors) && response.errors.length > 0) {
  return [{
    json: {
      ...prep,
      ok: false,
      semConflito: false,
      _statusCode: 500,
      erro: 'erro_monday_conflitos',
      mensagem: response.errors.map(e => e.message).join(' | '),
      errors: response.errors
    }
  }];
}

const COL = {
  NOME_EMPREGADO: 'dropdown_mktadatt',
  CHAPA: 'texto',
  DATA_INICIO: 'date_mktayxhb',
  DATA_FIM: 'date_mktasnwq',
  STATUS_CONVOCACAO: 'color_mm3a8ana',
  CANCELAMENTO_INICIO: 'date_mm3b88ta'
