// ==============================================================
// Trava de convocacao conflitante - WF7
// Respeita cancelamento parcial: somente o trecho ainda valido bloqueia.
// ==============================================================

const prep = $('Validar e preparar').first().json;
const response = $input.first().json || {};

if (Array.isArray(response.errors) && response.errors.length > 0) {
  return [{
    json: {
      ...prep,
      ok: false,
      semConflito: false,
      _statusCode: 500,
      erro: 'erro_monday_conflitos',
      mensagem: response.errors.map(e => e.message).join(' | '),
      errors: response.errors
    }
  }];
}

const COL = {
  NOME_EMPREGADO: 'dropdown_mktadatt',
  CHAPA: 'texto',
  DATA_INICIO: 'date_mktayxhb',
  DATA_FIM: 'date_mktasnwq',
  STATUS_CONVOCACAO: 'color_mm3a8ana',
  CANCELAMENTO_INICIO: 'date_mm3b88ta'
};

function normCode(v) { return String(v || '').replace(/\D/g, '').replace(/^0+/, '') || String(v || '').trim().toUpperCase(); }
function normName(v) { return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase().replace(/\s+/g, ' ').trim(); }
function colsOf(item) {
  const out = {};
  for (const c of item.column_values || []) out[c.id] = c.text || '';
  return out;
}
function addDays(iso, delta) {
  const d = new Date(iso + 'T00:00:00Z');
  if (Number.isNaN(d.getTime())) return null;
  d.setUTCDate(d.getUTCDate() + delta);
  return d.toISOString().slice(0, 10);
}
function effectivePeriod(start, end, statusLabel, cancelStart) {
  if (!start || !end) return null;
  const status = normName(statusLabel);
  if (status === 'CANCELADA' || status === 'CANCELADO' || status === 'BLOQUEADA - CONFLITO') return null;
  if (status === 'CANCELADA PARCIALMENTE' || status === 'CANCELADO PARCIALMENTE') {
    if (!cancelStart) return { start, end };
    const effectiveEnd = addDays(cancelStart, -1);
    if (!effectiveEnd || effectiveEnd < start) return null;
    return { start, end: effectiveEnd };
  }
  return { start, end };
}
function overlaps(aStart, aEnd, bStart, bEnd) {
  if (!aStart || !aEnd || !bStart || !bEnd) return false;
  return aStart <= bEnd && bStart <= aEnd;
}

const currentHasChapa = !!String(prep.empregadoChapa || '').trim();
const currentIdentity = currentHasChapa
  ? normCode(prep.empregadoChapa)
  : normName(prep.empregadoNome);

const items = response.data?.items_page_by_column_values?.items || [];

let conflito = null;
for (const item of items) {


  const cols = colsOf(item);
  const existingIdentity = currentHasChapa
    ? normCode(cols[COL.CHAPA])
    : normName(cols[COL.NOME_EMPREGADO] || item.name);
  if (!existingIdentity || existingIdentity !== currentIdentity) continue;

  const periodo = effectivePeriod(
    cols[COL.DATA_INICIO],
    cols[COL.DATA_FIM],
    cols[COL.STATUS_CONVOCACAO],
    cols[COL.CANCELAMENTO_INICIO]
  );
  if (!periodo) continue;
  if (!overlaps(periodo.start, periodo.end, prep.dataInicio, prep.dataFim)) continue;

  conflito = {
    item_id: String(item.id),
    item_url: 'https://contato-serv.monday.com/boards/18413180912/pulses/' + item.id,
    nome: item.name,
    chapa: cols[COL.CHAPA] || '',
    data_inicio: periodo.start,
    data_fim: periodo.end,
    data_inicio_original: cols[COL.DATA_INICIO] || '',
    data_fim_original: cols[COL.DATA_FIM] || '',
    status_convocacao: cols[COL.STATUS_CONVOCACAO] || '',
    data_inicio_cancelamento: cols[COL.CANCELAMENTO_INICIO] || ''
  };
  break;
}

if (conflito) {
  return [{
    json: {
      ...prep,
      ok: false,
      semConflito: false,
      _statusCode: 409,
      erro: 'convocação_conflitante',
      mensagem: 'Data divergente: este intermitente já foi convocado neste período.',
      conflito,

    }
  }];
}

return [{ json: { ...prep, ok: true, semConflito: true } }];

